spec.outputArgumentsSchemaV2:
{
  "type": "object",
  "required": [
    "complianceStatus",
    "vetoCodes",
    "flagCodes",
    "checksPerformed",
    "reasoning"
  ],
  "properties": {
    "complianceStatus": {
      "type": "string",
      "description": "PASS, VETO, or FLAG. VETO if any veto code; else FLAG if any flag code; else PASS"
    },
    "vetoCodes": {
      "type": "array",
      "description": "Veto reason codes from the approved list only",
      "items": {
        "type": "string"
      }
    },
    "flagCodes": {
      "type": "array",
      "description": "Flag reason codes from the approved list only",
      "items": {
        "type": "string"
      }
    },
    "checksPerformed": {
      "type": "array",
      "description": "Names of checks executed",
      "items": {
        "type": "string"
      }
    },
    "dtiRatio": {
      "type": "number",
      "description": "Debt-to-income ratio if computable (monthly debts / monthly income), else empty"
    },
    "reasoning": {
      "type": "string",
      "description": "Concise per-check summary citing the record fields relied on"
    },
    "notes": {
      "type": "string",
      "description": "Observations or data gaps a reviewer should see"
    }
  }
}

